var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"놀랍군. 이성을 잃은 것 같아 보이지만 적과 아군을 확실하게 구분해서 베고 있어.","JPN":"これは驚いた。理性を無くしたように見えるが、敵と味方を確実に見分けて斬っている。","ENG":"Impressive. While she seems to have lost cognition, she is able to identify enemies and allies apart.","TWN":"真驚人，看似失去理智，攻擊時卻還能清楚分別敵我。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"게다가 저 힘은…… 단순히 적신인자의 효과라고 하기엔 격차가 크다.","JPN":"それにあの力は……単なるクリムゾン・ファクターの効果というには差がありすぎる。","ENG":"And that strength... Far more powerful than the basic effect of the embedded factor.","TWN":"而且她的力量之大……不單純是適神因子的效果。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"어쩌면 내가 상정하지 못한 변수가 있는 건가?","JPN":"もしかすると私が想定していない変数があるのか？","ENG":"Perhaps there is a variable that I might have missed?","TWN":"難道是我沒計算到的變數？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아하핫, 무식하게 날뛰는 모습이 그야말로 짐승이네.","JPN":"あははっ、無知性で暴れてるところなんて獣そっくり。","ENG":"Ah ha ha, look at her go berserk. A true savage, no?","TWN":"哈哈哈，根本是野獸吧，在那橫衝直撞的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크아아아아!!!!</color>","JPN":"<color=#ff3636>クアアアア！！！！</color>","ENG":"<color=#ff3636>Gwaaaah!!!</color>","TWN":"<color=#ff3636>呃啊啊啊阿！！！！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저 흑색의 검은…… 설마 명부검?","JPN":"あの黒色の剣は……まさか冥府剣？","ENG":"That dark blade... Could it be the Nether God’s Sword?","TWN":"那把黑色的劍……難道是冥府劍？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그때 환상종 여인이 가지고 있던 검이군. 아는 물건이오?","JPN":"あの時幻想種の女が持っていた刀だな。知っているのか？","ENG":"It was the sword that the Bygone female was holding. Is it something familiar to you?","TWN":"是上次那個夢幻類女生拿的劍，你知道這把劍？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"알다마다. 명부신의 자손들이 역신을 베기 위해 벼려낸 명부신의 검이지.","JPN":"もちろん知っておるとも。冥府の神の子孫が疫病神を斬るために鍛えた冥府の神の刀だ。","ENG":"Of course it is. It was used by the Nether God to slay the Plague God.","TWN":"當然知道，那是冥府神的後裔鑄造來斬殺瘟神的劍。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"오랫동안 미완성인 상태라고 들었는데, 그럼에도 저런 엄청난 위력을 발휘할 줄이야.","JPN":"長らく未完成のままだと聞いていたが、それでもあんな威力を発揮するとは。","ENG":"I heard that it was left unfinished for a long time... but even in that state, its powers seem impeccable.","TWN":"但我聽說一直處於未完成的狀態，沒想到可以發揮如此大的威力。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"신의 검이라…… 그렇다면 왜 저렇게 강해졌는지도 납득이 되는군.","JPN":"神の剣か……それならどうしてあんなに強くなったのかも納得がいく。","ENG":"A god’s sword... That explains the massive increase in power.","TWN":"神之劍嗎……那就不難理解為何會有如此威力。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그렇게 마냥 감탄하고 있을 상황은 아닌 것 같은데.","JPN":"そんなに感心している場合ではないぞ。","ENG":"This is not the time to stand and watch in awe.","TWN":"現在不是讚嘆的時候吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그 무모한 실험 때문에 아까운 전력들이 전부 쓸려나가고 있지 않나?","JPN":"その無茶な実験のせいで貴重な戦力が全部失われようとしているではないか。","ENG":"Your troops are getting butchered because of your reckless experiment.","TWN":"因為你那衝動的實驗，一直在耗損那些珍貴的戰力！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"희생을 두려워하면 이상적인 실험 결과를 얻기 힘들다오.","JPN":"犠牲を恐れていては理想的な実験結果を得ることは難しい。","ENG":"The fear of loss is what keeps us away from the ideal.","TWN":"害怕犧牲，就無法得到理想的實驗結果。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만, 슬슬 실험의 전제를 바꿔보는 것도 괜찮겠지.","JPN":"だが、そろそろ実験の前提を変えてみるのもいいだろう。","ENG":"Nevertheless... It would be a valid notion to change the prerequisites of the experiment.","TWN":"不過稍微改變一下實驗的條件也無妨。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어, 시작하거라.","JPN":"レノア、始めろ。","ENG":"Begin, Lenore.","TWN":"蕾諾雅，開始吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흣…… 우후훗……","JPN":"ふっ……うふふっ……","ENG":"Heh... Fu fu fu...","TWN":"呵……呵呵呵……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저, 저 녀석…… 왜 자길 찌르는 거지?! 미친 건가?","JPN":"あ、あいつ……どうして自分を刺したのだ！？　狂いでもしたのか？","ENG":"Th-that girl... She’s suddenly stabbing herself! Why?!","TWN":"她…她……她為何要戳自己？她瘋啦？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"모든 생물은 궁지에 몰렸을 때 초인적인 본능을 발현하기 마련이오.","JPN":"すべての生き物は切羽詰まった時に超人的な本能を発揮する。","ENG":"At the verge of death, all living organisms have a tendency to show instincts beyond their limits.","TWN":"當生物面對絕境時，就會激發出超能力。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어가 가진 예견 능력 또한 마찬가지……","JPN":"レノアが持っている予言の能力もまた同じ……","ENG":"Lenore’s foresight abilities included...","TWN":"蕾諾雅的預知能力也是……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"신경과 이어진 칼날들이 적의 앞 수를 읽어내는 동시에 움직이게 되지.","JPN":"神経と繋がっている刃が敵の手を読むと同時に動くようになる。","ENG":"The blades connected to her nerve systems will move as soon as she predicts the enemy’s movements.","TWN":"連結神經的刀刃在讀取敵人下一步的同時行動。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"당장 눈앞에 칼을 휘두르는 상대가 있는데, 자해 같은 걸로 될 리가……!","JPN":"目の前に攻撃してくる相手がいるのに、自傷なんかでどうにかできるわけが……！","ENG":"Self-harm is not going to work from a berserk samurai–","TWN":"敵人就正在眼前舞刀弄槍的，還有時間在那邊自殘……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크으으……!</color>","JPN":"<color=#ff3636>くうう……！</color>","ENG":"<color=#ff3636>Khhhggh...!</color>","TWN":"<color=#ff3636>呃呃呃……！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"후훗, 이 하등한 실험체 년이……","JPN":"ふふっ、この下等な実験体が……","ENG":"Fu fu, you’re nothing but an inferior test subject...","TWN":"呵呵，你這低等的實驗體……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"감히 아버지를 공격하려 해?","JPN":"お父様を攻撃しようとするなんて。","ENG":"How dare you try to harm father?","TWN":"好大膽子，竟然想攻擊父親？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"정말로…… 전세가 바뀌었잖아?","JPN":"本当に……戦況が変わった？","ENG":"So it’s true... She did get stronger.","TWN":"竟然真的……扭轉局勢了？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크으윽……!</color>","JPN":"<color=#ff3636>くううっ……！</color>","ENG":"<color=#ff3636>Urrrghhh...!</color>","TWN":"<color=#ff3636>呃呃呃……！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이대로 죽여버릴까요? 아버지?","JPN":"このまま殺しましょうか？　お父様。","ENG":"Should I kill her, father?","TWN":"父親，要乾脆殺掉她嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"아니, 예상 밖의 흥미로운 적성체를 찾았다.","JPN":"いや、予想外の興味深い適性体が見つかった。","ENG":"No, she is such an interesting sample.","TWN":"不，真是意外，找到不錯的實驗對象呢。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"제대로 된 적신인자를 사용했을 때 어떤 반응을 보일지 기대되는군.","JPN":"正式なクリムゾン・ファクターを使用した時にはどんな反応を見せてくれるか楽しみだ。","ENG":"I look forward to how she will react once we inject the completed embedded factor.","TWN":"我很期待，若是使用合適的適神因子不知道會有何反應。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇지 않소, 하바키?","JPN":"そう思わないか？　覇吐。","ENG":"Do you not agree, Habaki?","TWN":"你說是不是，幅木？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"……소란을 너무 피웠어. 여기선 일단 철수하지.","JPN":"……暴れすぎだ。ここはひとまず撤退しよう。","ENG":"...I say we leave now. We made too much of a racket here.","TWN":"……現在事情鬧得有點大，還是先撤退吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"뒤는 맡기겠다, 레노어.","JPN":"後は任せたぞ、レノア。","ENG":"I leave the rest to you, Lenore.","TWN":"後面就交給你了，蕾諾雅。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……어딜 가려고 하느냐?","JPN":"……どこへ行く。","ENG":"...Where do you think you are going?","TWN":"……想逃去哪？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흥, 여기까지 쫓아온 건가? 끈질긴 것.","JPN":"ふん、ここまで追ってきたのか？　しつこいやつめ。","ENG":"Hmph, you followed us all the way here? How unpleasantly persistent.","TWN":"哼，竟然追到這裡來，還真難纏。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키, 이 참상은 전부 네 놈이 저지른 짓이더냐?","JPN":"覇吐、この惨状はすべてお前がやったのか？","ENG":"Is this bloodbath all your wrongdoings, Habaki?","TWN":"幅木，這副慘狀全是你造成的嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"결국 가문연합을 위한 일이다. 전통에 얽매여 변화를 두려워하는 너희 같은 겁쟁이들을 대신해 행동하는 것이지.","JPN":"結局は連合を思ってのことだ。伝統に縛られ変化を恐れるお前たちのような臆病者の代わりをしてやっているのだ。","ENG":"This will eventually profit the Alliance. I am merely doing what you tradition-devoured cowards are afraid of doing.","TWN":"這全是為家族聯盟好，你們這些拘泥於傳統，害怕改變的膽小鬼，我只是代替你們做你們該做的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"아성에 귀가 멀어 선조들의 목소리조차 두려워하지 못하게 됐구나.","JPN":"驕りのあまり、ご先祖様に対する畏敬の念さえも忘れたか。","ENG":"Your arrogance has not only pulled you away from the voices of our ancestors, but it has also deafened your senses of fear and respect.","TWN":"你現在是天高皇帝遠，所以連祖先的叮嚀也沒在怕嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"입만 살았군. 어미가 죽은 뒤로 검도 제대로 쥐지 못하게 된 주제에.","JPN":"よく言うわ。母親が死んだ後からまともに刀も握れぬ者が。","ENG":"Fancy talk will not hide your cowardliness. You cannot even wield your own sword after your mother died.","TWN":"一個在媽媽死掉後連劍都拿不好的人，有什麼資格對我說教？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"읏?!","JPN":"うっ！？","ENG":"Ngh?!","TWN":"唔？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지께서 너무 죽이지는 말라고 하셨지만……","JPN":"お父様が殺さないようにとおっしゃったけど……","ENG":"Father told me to go easy on you...","TWN":"父親要我別大開殺戒……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"자꾸 건방지게 굴면 죽일 거야.","JPN":"調子に乗ると殺すわよ。","ENG":"But keep talking like that, and I swear I’ll rip you apart.","TWN":"你最好收斂一點，否則休怪我刀下不留人。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……너, 그 눈은 설마……?","JPN":"……お前、その目はまさか……？","ENG":"...You...! Those eyes…?","TWN":"……你的眼睛，莫非……？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"큿……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"唔……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그런 무거운 걸 들고 잘도 피하네.","JPN":"そんな重いのを持ってるわりにはうまく避けてるわね。","ENG":"Look at how fast you move with that heavy sword.","TWN":"拿著那麼重的劍還是很會躲嘛。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"다음 번엔 확실하게……","JPN":"でも次は確実に……","ENG":"Next time, I’ll make sure to–","TWN":"下次見面……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"멈추세요!","JPN":"おやめなさい！","ENG":"Stop!","TWN":"住手！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 이상 날뛰는 것은 용납하지 않겠습니다.","JPN":"それ以上暴れることは許しません。","ENG":"I will not allow any more violence.","TWN":"我不允許你再繼續這樣恣意妄為！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……음? 이 에너지 파형은?","JPN":"……む？　このエネルギーの波形は？","ENG":"...Mm? This energy wave...","TWN":"……嗯？這股能量波形是？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님?","JPN":"ご当主様？","ENG":"Lady Nanahara?","TWN":"堂主？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"항상 등장이 늦네, 원본.","JPN":"やっと来たのね、オリジナル。","ENG":"You’re always late, Original.","TWN":"你老是慢一步呢，正本。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이번에야 말로 누가 더 위에 있는지 결착을 지어볼까?","JPN":"今度こそ誰が上なのか決着つけてみる？","ENG":"Why don’t we really settle things out? The superior and the inferior.","TWN":"來分個高下吧？看誰到底比較厲害！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어, 철수한다.","JPN":"レノア、撤退するぞ。","ENG":"Retreat, Lenore.","TWN":"蕾諾雅，收手。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네? 하지만 아버지의 실험체가……","JPN":"え？　ですが、お父様の実験体が……","ENG":"Huh? But father, your test subject–","TWN":"什麼？可是父親的實驗體……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"샘플 확보는 다음으로 미룬다. 지금은 저들에게 넘겨라.","JPN":"サンプルの確保は後回しだ。今はあの者たちに渡せ。","ENG":"We will secure the sample later. For now, let them have her.","TWN":"下次再取得樣本，這次先交給她們吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다! 무슨 소리인가! 목표가 눈 앞에 있는데 물러나다니!","JPN":"ユダ！　何を言うのだ！　目標が目の前にいるのに引き下がるだと！","ENG":"This is absurd, Judas! The target is standing right before us!","TWN":"尤達！你在胡說什麼！目標就近在眼前，你現在要撤退？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하바키, 그대의 목적은 원본을 되도록 온전한 상태로 확보하는 것이었지.","JPN":"覇吐、そなたの目的はオリジナルをなるべく傷のない状態で確保することであったな。","ENG":"Your goal was to acquire the Original unharmed, Habaki.","TWN":"幅木，你的目標是要毫髮無傷地取得正本吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어, 지금 네 힘으로 원본을 훼손하지 않고 포획할 수 있겠느냐?","JPN":"レノア、今のお前の力でオリジナルを傷つけず捕獲できるか？","ENG":"What do you say, Lenore? Do you think you could capture her without damaging her?","TWN":"蕾諾雅，以你現在的力量，你有把握可以不傷到正本嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"일단은 물러나는 게 좋겠어요, 아버지.","JPN":"ここは撤退した方が良さそうですわ、お父様。","ENG":"I think we should call it a day for now, father.","TWN":"父親說的是，還是先撤退吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"쳇……","JPN":"ちっ……","ENG":"Tch...!","TWN":"嘖……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_NPC_NANAHARA_NULL","text":{"KOREA":"적들이 도망칩니다. 쫓을까요?","JPN":"敵が逃げます。追いかけましょうか？","ENG":"Enemies retreating. Should we track them down?","TWN":"敵人逃跑了，要追嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……아뇨. 저들은 아직 도시를 벗어나지 못했어요.","JPN":"……いいえ。あの者たちはまだ都市から出ていません。","ENG":"...No. They are yet to leave this city.","TWN":"……不用，他們暫時逃不出這座城市的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"기회는 다음으로 미루고 지금은 부상자들을 챙기는 게 우선입니다.","JPN":"それは今度にして今は怪我人の世話が先です。","ENG":"We will wait for our next opportunity. For now, our top priority is to tend the injured.","TWN":"下次還有機會，先處理傷者吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"작은 당주.","JPN":"チビ当主。","ENG":"Ladychild.","TWN":"小堂主，"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"인간에게 신력을 함부로 쓰려고 하지 마라. 금기를 어기는 행동이다.","JPN":"人間にむやみに神力を使おうとするでない。禁忌を破る行動じゃ。","ENG":"Don’t go ahead using divine powers against humans. That’s a rule breaker.","TWN":"請勿隨意對人類使用神力，這是觸犯禁忌的行為。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네, 주의하겠습니다.","JPN":"……はい、気をつけます。","ENG":"...Understood, Miss Nao.","TWN":"……好的，我會注意。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"다…… 당주님……","JPN":"と……ご当主様……","ENG":"M-my... lady...","TWN":"堂…… 堂主……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"남동방대장?","JPN":"南東軍隊長？","ENG":"Southeastern Captain?","TWN":"東南方隊長？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_NULL","text":{"KOREA":"하바키는…… 당주님을 찾고 있습니다……","JPN":"覇吐は……ご当主様を探していました……","ENG":"Habaki... he’s looking for you...","TWN":"幅木……要找的人是您……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_NULL","text":{"KOREA":"그러니 부디…… 조심……","JPN":"どうか……お気をつけ……","ENG":"Please... take care...","TWN":"您千萬……要小心……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"잠시만 버텨주세요! 금방 치료를……!","JPN":"もう少し頑張ってください！　すぐに治療を……！","ENG":"Stay with me just a little more! I’ll heal–","TWN":"你再撐一下！我馬上替你治……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"경동맥을 끊고 심장을 관통했습니다. 이미 살릴 수 있는 상태가 아니었군요.","JPN":"頸動脈を切り心臓を貫通しておりました。すでに助けられる状態ではありませんでした。","ENG":"The weapon cut the coronary artery and pierced the heart. This is an injury beyond saving.","TWN":"頸動脈斷裂，而且貫穿心臟，救不活的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……어째서죠?","JPN":"……どうしてですか？","ENG":"...Why?","TWN":"……為什麼？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저들은 왜 이렇게까지 무고한 사람들을 해치는 건가요?","JPN":"あの者たちはどうしてここまで何の罪もない人たちを傷つけるのですか？","ENG":"Why did they harm these innocent people?","TWN":"為什麼要傷害無辜的人？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"남동방대장이 남긴 말대로라면…… 이번에 하바키가 벌인 짓은 당주님과 연관이 있어 보이는군요.","JPN":"南東軍隊長の残した言葉どおりなら……今度覇吐がしでかしたことはご当主様と関係があるようです。","ENG":"Judging from what the Southeastern Captain said... Habaki’s doings is to supposedly lure you, my lady.","TWN":"根據東南方隊長的遺言……幅木這次之所以會做出這些事，原因和堂主有關。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……부탁드려요, 사나에.","JPN":"……お願いします、早苗。","ENG":"...Please, Sanae.","TWN":"……早苗，我要拜託你一件事。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"태스크포스 노아의 사람들에 대해 조사해주세요.","JPN":"タスクフォース・ノアの人たちについて調査してください。","ENG":"Bring me a report on the members of TASKFORCE NOA.","TWN":"請你替我調查一下特遣勢力中的諾亞。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"분부대로.","JPN":"御意。","ENG":"As you wish.","TWN":"是，遵命。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라 당주. 여기 생존자 하나 더 찾았다.","JPN":"七原家当主。ここにもう一人生き残りがいるぞ。","ENG":"Lady Nanahara. We found another survivor over here.","TWN":"七原堂主，這裡發現一名倖存者，"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"상태가 그리 좋지는 않아 보이지만 말이지.","JPN":"あまり具合が良くないようじゃが。","ENG":"She doesn’t look like she’s in good shape, though.","TWN":"不過她的狀態看起來不太好。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};